meta-properties.dotnet11-properties:
					NomadEnvironment.GetTrace().Info("****** Ofertas Laborales por Vencer ******");
Nomad.Base.Mail.OutputMails.MAIL MyMAIL;
Nomad.Base.Mail.OutputMails.DESTINATARIO MyDEST;

NomadXML docParam = NomadEnvironment.QueryNomadXML(OFERTA_LAB.Resources.getParametro, "").FirstChild();
NomadEnvironment.GetTrace().Info("docParam: " + docParam.ToString());                                

string IdPersonal="";                                                                 
string contenido="";
MyMAIL= new Nomad.Base.Mail.OutputMails.MAIL();
for (NomadXML OfLab=docParam.FirstChild(); OfLab!=null; OfLab=OfLab.Next())
{                                                                         
	if(IdPersonal == OfLab.GetAttr("oi_personal")) {
		contenido+= "La Oferta Laboral " + OfLab.GetAttr("c_oferta_lab") + " está próxima a vencer. Restan " + OfLab.GetAttr("diff") + " días para su vencimiento. \n"     ;
		NomadEnvironment.GetTrace().Info("MyMAIL -- agregar ofertas labs " + MyMAIL.SerializeAll());	
	} else {
		if(IdPersonal!="") {
			MyMAIL.CONTENIDO = contenido;
			NomadEnvironment.GetTrace().Info("MyMAIL-- " + MyMAIL.SerializeAll());	
			NomadEnvironment.GetCurrentTransaction().SaveRefresh(MyMAIL); 		
		}
		IdPersonal = OfLab.GetAttr("oi_personal");
		MyMAIL= new Nomad.Base.Mail.OutputMails.MAIL();
		MyMAIL.ASUNTO= "Próximos vencimientos de Ofertas Laborales";
		MyMAIL.DESDE_APLICACION=NomadProxy.GetProxy().AppName;
		MyMAIL.FECHA_CREACION=System.DateTime.Now;
		contenido = "La Oferta Laboral " + OfLab.GetAttr("c_oferta_lab") + " está próxima a vencer. Restan " + OfLab.GetAttr("diff") + " días para su vencimiento. \n"     ;
		MyDEST=new Nomad.Base.Mail.OutputMails.DESTINATARIO(); 
		MyDEST.ENTIDAD=OfLab.GetAttr("d_usuario");
	  MyMAIL.DESTINATARIOS.Add(MyDEST);
	}
}
MyMAIL.CONTENIDO = contenido;
NomadEnvironment.GetTrace().Info("MyMAIL-- " + MyMAIL.SerializeAll());	
NomadEnvironment.GetCurrentTransaction().SaveRefresh(MyMAIL);

