					for $r in SQL('
{%? (#SOURCE:@START='') {% %} {% fromrow {%=#SOURCE:@START %} %} %} 
 {%? (#SOURCE:@LEN='') {% %} {% maxsize {%=#SOURCE:@LEN %} %} %} 
select
  POS03_OFERTAS_LAB.oi_oferta_lab as ID,
  POS03_OFERTAS_LAB.c_oferta_lab as COD,
  POS03_OFERTAS_LAB.d_oferta_lab as DES
from
  POS03_OFERTAS_LAB
Where
  (POS03_OFERTAS_LAB.f_cierre > Now() or ISNULL(POS03_OFERTAS_LAB.f_cierre))
{%? (#SOURCE:@OI_FIND='') {% %} {% and ID={#SOURCE:@OI_FIND} %} %} 
{%? (#SOURCE:@TXT_FIND='') {% %} {% and (contain(DES,{#SOURCE:@TXT_FIND}) or contain(COD,{#SOURCE:@TXT_FIND})) %} %} 
{%? (#SOURCE:@OI_PARENT='') {% %} {% and PARENT={#SOURCE:@OI_PARENT} %} %} 

{%? (#SOURCE:@WHERE='') {% %} {% and {%=#SOURCE:@WHERE %} %} %}
{%? (#SOURCE:@ORDERBY='') {% order by DES asc %} {%  order by {%=#SOURCE:@ORDERBY %} asc %} %}')/ROWS/ROW

		for $r in SQL
('  
	{%?($PARAM/@qryMode='LISTOL')
	{%	

  	{%?($PARAM/@fromrow!='') {%fromrow {%=$PARAM/@fromrow%}%} {% %} %}
  	{%?($PARAM/@maxsize!='') {%maxsize {%=$PARAM/@maxsize%}%} {% %} %}

		SELECT
		OL.oi_oferta_lab,
		OL.c_oferta_lab,
		OL.d_oferta_lab,
		OL.f_oferta_lab,
		OL.f_cierre,
		PER.d_ape_y_nom

	%} {% %} %}				



	{%?($PARAM/@qryMode='COUNTOL')
	{%
	   SELECT 				   
	   count(OL.oi_oferta_lab) as cantTotal				   
	%} {% %} %}

	FROM
		POS03_OFERTAS_LAB as OL,				 
		PER01_PERSONAl as PER

		JOIN
		OL.oi_personal LEFT OUTER PER.oi_personal	


	WHERE 1=1
	{%?($PARAM/@estado='T') {%AND 1 = 1	%} {% %} %}
	{%?($PARAM/@estado='A') {%AND (isNull(OL.f_cierre)OR (OL.f_cierre > Now() ) ) %} {% %} %}		  
	{%?($PARAM/@estado='C') {%AND (isNotNull(OL.f_cierre) AND (OL.f_cierre < Now() ) ) %} {% %} %}

	{%?($PARAM/@campo_buscar!='') 
		{% AND 
		(
			contain(OL.c_oferta_lab,{$PARAM/@campo_buscar}) OR
			contain(OL.d_oferta_lab,{$PARAM/@campo_buscar}) OR
			contain(OL.f_oferta_lab,{$PARAM/@campo_buscar}) OR
			contain(OL.f_cierre,{$PARAM/@campo_buscar}) 	OR
			contain(PER.d_ape_y_nom,{$PARAM/@campo_buscar}) OR
			contain(OL.o_oferta_lab,{$PARAM/@campo_buscar})			
		) 
		%} 
	{% %} %}		 		 

	{%?($PARAM/@f_alta_desde!='') {% AND OL.f_oferta_lab >={$PARAM/@f_alta_desde} %} {% %} %}
	{%?($PARAM/@f_alta_hasta!='') {% AND OL.f_oferta_lab <={$PARAM/@f_alta_hasta} %} {% %} %}
	{%?($PARAM/@f_cierre_desde!='') {% AND OL.f_cierre >={$PARAM/@f_cierre_desde} %} {% %} %}
	{%?($PARAM/@f_cierre_hasta!='') {% AND OL.f_cierre <={$PARAM/@f_cierre_hasta} %} {% %} %}

	{%?($PARAM/@filtroPersona!='') {% AND LIKE(PER.d_ape_y_nom,\'%{%=$PARAM/@filtroPersona%}%\') %} {% %} %}

	{%?($PARAM/@oi_empresa!='') {% AND OL.oi_empresa = {$PARAM/@oi_empresa} %} {% %} %} 			
	{%?($PARAM/@oi_tipos_serv!='') {% AND OL.oi_tipos_serv = {$PARAM/@oi_tipos_serv} %} {% %} %} 			 			
	{%?($PARAM/@oi_pais!='') {% AND OL.oi_pais = {$PARAM/@oi_pais} %} {% %} %} 			 			
	{%?($PARAM/@oi_provincia!='') {% AND OL.oi_provincia = {$PARAM/@oi_provincia} %} {% %} %} 			 			
	{%?($PARAM/@oi_localidad!='') {% AND OL.oi_localidad = {$PARAM/@oi_localidad} %} {% %} %} 			 			

	{%?($PARAM/@qryMode='LISTOL') 
		{%
	ORDER BY {%=$PARAM/@campo%} {%=$PARAM/@criterio%}		 
	%} {% %} %}

')/ROWS/ROW

